const arr = Array.isArray($json) ? $json : (Array.isArray($json.body) ? $json.body : []);

const active = arr.filter(a => a?.status?.state === 'active');
const critical = active.filter(a => (a?.labels?.severity || '').toLowerCase() === 'critical');
const warning = active.filter(a => (a?.labels?.severity || '').toLowerCase() === 'warning');

const now = new Date();
const isSunday = now.getDay() === 0;

const top = active.slice(0, 6).map(a => {
  const name = a?.labels?.alertname || 'unknown';
  const sev = a?.labels?.severity || 'unknown';
  const inst = a?.labels?.instance || 'n/a';
  return `- ${name} (${sev}) @ ${inst}`;
});

const health = critical.length > 0 ? 'CRITICAL' : (warning.length > 0 ? 'WARNING' : 'OK');

const brief = [
  `RESUMEN DIARIO [${health}]`,
  `Fecha: ${now.toISOString()}`,
  `Alertas activas: ${active.length} (critical: ${critical.length}, warning: ${warning.length})`,
  active.length ? `Top: ${active[0]?.labels?.alertname || 'n/a'}` : 'Sin alertas activas.'
].join('\n');

const sunday = [
  `PUNTO DE SITUACION SEMANAL [${health}]`,
  `Fecha: ${now.toISOString()}`,
  `Alertas activas: ${active.length} (critical: ${critical.length}, warning: ${warning.length})`,
  '',
  ...(top.length ? top : ['- Sin alertas activas']),
  '',
  'Accion recomendada:',
  health === 'OK' ? '- Sistema estable. No requiere accion inmediata.' : '- Revisar Grafana/Alertmanager y priorizar alertas critical.'
].join('\n');

return [{ json: { message: isSunday ? sunday : brief } }];

const arr = Array.isArray($json) ? $json : (Array.isArray($json.body) ? $json.body : []);
const active = arr.filter(a => a?.status?.state === 'active');
const critical = active.filter(a => (a?.labels?.severity || '').toLowerCase() === 'critical');
const warning = active.filter(a => (a?.labels?.severity || '').toLowerCase() === 'warning');

const now = Date.now();
const currentState = critical.length > 0 ? 'CRITICAL' : (warning.length > 0 ? 'WARNING' : 'OK');

const store = $getWorkflowStaticData('global');
const lastState = store.lastState || 'OK';
const lastSent = Number(store.lastSent || 0);

let shouldSend = false;
if (currentState !== lastState) shouldSend = true;
if (currentState !== 'OK' && now - lastSent > 6 * 60 * 60 * 1000) shouldSend = true;

store.lastState = currentState;
if (shouldSend) store.lastSent = now;

if (!shouldSend) return [];

const header = currentState === 'OK' ? 'GUARD RESUELTO' : 'GUARD ALERTA';
const summary = active.slice(0, 5).map(a => `- ${a?.labels?.alertname || 'unknown'} (${a?.labels?.severity || 'n/a'}) @ ${a?.labels?.instance || 'n/a'}`).join('\n');

const message = [
  header,
  `Hora: ${new Date().toISOString()}`,
  `Estado: ${currentState}`,
  `Alertas activas: ${active.length} (critical: ${critical.length}, warning: ${warning.length})`,
  summary || '- Sin alertas activas'
].join('\n');

return [{ json: { message } }];
